import{_ as t,o as i,c as a,ae as n}from"./chunks/framework.DOXEjmrP.js";const g=JSON.parse('{"title":"English Listen - Professional English Dictation Training Tool","description":"","frontmatter":{},"headers":[],"relativePath":"en/english-listen.md","filePath":"en/english-listen.md"}'),r={name:"en/english-listen.md"};function o(l,e,s,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="english-listen-professional-english-dictation-training-tool" tabindex="-1">English Listen - Professional English Dictation Training Tool <a class="header-anchor" href="#english-listen-professional-english-dictation-training-tool" aria-label="Permalink to &quot;English Listen - Professional English Dictation Training Tool&quot;">​</a></h1><p>Tired of boring English dictation training? Try <strong>English Listen</strong> — a modern dictation tool that makes you fall in love with English learning!</p><h2 id="project-introduction" tabindex="-1">Project Introduction <a class="header-anchor" href="#project-introduction" aria-label="Permalink to &quot;Project Introduction&quot;">​</a></h2><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>English Listen is an intelligent dictation software designed specifically for English learners. Developed based on C++17 and Qt6, it supports Windows platform. It&#39;s not just a word player, but a secret weapon to improve your listening and spelling skills. Whether you&#39;re a student, teacher, or self-learner, it can help you easily handle English dictation.</p><h3 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h3><ul><li><strong>Intelligent Vocabulary Management</strong>: Support for flexible editing, multi-level classification, batch operations, and automatic saving</li><li><strong>Personalized Training Control</strong>: Free adjustment of reading intervals, pause/resume, quick navigation, and repeat playback</li><li><strong>Visual Experience Optimization</strong>: Dark/light theme switching, system theme adaptation, and smooth animation effects</li><li><strong>Learning Progress Tracking</strong>: Score recording, data visualization charts, multi-dimensional analysis, and history management</li><li><strong>Dual Voice Engines</strong>: Support for Windows SAPI and Flite third-party engines, available offline</li><li><strong>Intelligent Dictation Modes</strong>: Flexible switching between paper-and-pencil mode and online mode</li><li><strong>Keyboard Shortcut Support</strong>: Convenient operations like spacebar repeat, arrow key switching, ESC pause, etc.</li></ul><h3 id="usage-scenarios" tabindex="-1">Usage Scenarios <a class="header-anchor" href="#usage-scenarios" aria-label="Permalink to &quot;Usage Scenarios&quot;">​</a></h3><ul><li><strong>Students</strong>: After-class English dictation practice to improve listening comprehension and spelling skills</li><li><strong>Teachers</strong>: Classroom dictation testing tool, supporting both paper-and-pencil and online modes</li><li><strong>Self-learners</strong>: Self-study English, track learning progress through visual charts</li><li><strong>Training institutions</strong>: As a teaching aid, providing professional dictation training functions</li></ul><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><h3 id="core-technologies" tabindex="-1">Core Technologies <a class="header-anchor" href="#core-technologies" aria-label="Permalink to &quot;Core Technologies&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technical Component</th><th>Version/Description</th><th>Purpose</th></tr></thead><tbody><tr><td>Programming Language</td><td>C++17</td><td>Main development language, modern C++ standard</td></tr><tr><td>GUI Framework</td><td>Qt6.5+</td><td>Cross-platform interface development framework</td></tr><tr><td>Build System</td><td>CMake 3.16+</td><td>Modern build tool</td></tr><tr><td>Compiler</td><td>MinGW-w64 GCC 11+</td><td>Windows platform compiler</td></tr></tbody></table><h3 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><ul><li><strong>Main Dependencies</strong>: <ul><li>Qt6 Core/Widgets/Multimedia (v6.5+)</li><li>Flite speech synthesis engine (v2.2+)</li><li>Windows SAPI (system built-in)</li></ul></li></ul><h3 id="development-environment" tabindex="-1">Development Environment <a class="header-anchor" href="#development-environment" aria-label="Permalink to &quot;Development Environment&quot;">​</a></h3><ul><li><strong>Recommended IDE</strong>: Qt Creator 10+/Visual Studio 2022/Clion</li><li><strong>Necessary Tools</strong>: CMake, Git, MinGW-w64</li><li><strong>Build Tools</strong>: Ninja (optional, improves build speed)</li></ul><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><h3 id="minimum-configuration" tabindex="-1">Minimum Configuration <a class="header-anchor" href="#minimum-configuration" aria-label="Permalink to &quot;Minimum Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 10 version 10.0.15063 (1703) or higher</td></tr><tr><td>Processor</td><td>Intel Pentium G5400 or equivalent performance processor</td></tr><tr><td>Memory</td><td>1GB RAM</td></tr><tr><td>Storage</td><td>50MB available hard disk space</td></tr><tr><td>Display</td><td>1024x768 resolution</td></tr><tr><td>Audio Device</td><td>Sound card and speakers/headphones that support audio playback</td></tr></tbody></table><h3 id="recommended-configuration" tabindex="-1">Recommended Configuration <a class="header-anchor" href="#recommended-configuration" aria-label="Permalink to &quot;Recommended Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 11 22H2 or higher</td></tr><tr><td>Processor</td><td>Intel Core i5-9300H or higher performance processor</td></tr><tr><td>Memory</td><td>4GB RAM or more</td></tr><tr><td>Storage</td><td>100MB available hard disk space</td></tr><tr><td>Display</td><td>1920x1080 resolution</td></tr><tr><td>Audio Device</td><td>High-quality audio equipment</td></tr></tbody></table><h2 id="hardware-requirements" tabindex="-1">Hardware Requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware Requirements&quot;">​</a></h2><h3 id="required-hardware" tabindex="-1">Required Hardware <a class="header-anchor" href="#required-hardware" aria-label="Permalink to &quot;Required Hardware&quot;">​</a></h3><ul><li>Computer with audio output support</li><li>Keyboard and mouse</li><li>Display</li></ul><h3 id="optional-hardware" tabindex="-1">Optional Hardware <a class="header-anchor" href="#optional-hardware" aria-label="Permalink to &quot;Optional Hardware&quot;">​</a></h3><ul><li>High-quality headphones or speakers (to enhance listening experience)</li><li>Microphone (for voice comparison function, supported in future versions)</li></ul><h3 id="special-requirements" tabindex="-1">Special Requirements <a class="header-anchor" href="#special-requirements" aria-label="Permalink to &quot;Special Requirements&quot;">​</a></h3><ul><li>No special hardware requirements, ordinary home computers can run smoothly</li></ul><h2 id="installation-and-usage" tabindex="-1">Installation and Usage <a class="header-anchor" href="#installation-and-usage" aria-label="Permalink to &quot;Installation and Usage&quot;">​</a></h2><h3 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h3><ol><li><strong>Download Installer</strong>: Download the latest version installer from <a href="#download-address">Download Address</a></li><li><strong>Run Installer</strong>: Double-click <code>EnglishListenSetup.exe</code> to start the installation wizard</li><li><strong>Select Installation Path</strong>: Follow the wizard prompts to select the installation directory (default: <code>C:\\Program Files\\EnglishListen</code>)</li><li><strong>Complete Installation</strong>: Click the &quot;Install&quot; button and wait for the installation to complete</li><li><strong>First Run</strong>: After installation, check &quot;Run English Listen&quot; to start the program</li></ol><h3 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h3><ol><li><strong>Start Program</strong>: Double-click the desktop shortcut or start from the start menu</li><li><strong>Add Words</strong>: Click the &quot;View Words&quot; button, enter the words to practice in the text box (one per line)</li><li><strong>Start Test</strong>: Click &quot;Start Dictation Test&quot;, select the dictation mode (paper-and-pencil mode or online mode)</li><li><strong>Dictation Practice</strong>: Write down the heard words according to the voice prompts</li><li><strong>Check Answers</strong>: After the test, click &quot;View Answers&quot; to check the results</li></ol><h3 id="advanced-configuration" tabindex="-1">Advanced Configuration <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;Advanced Configuration&quot;">​</a></h3><ul><li><strong>Voice Engine Settings</strong>: Select SAPI or Flite engine in the settings dialog</li><li><strong>Time Interval Adjustment</strong>: Adjust the reading interval (1-10 seconds) in the test interface</li><li><strong>Theme Switching</strong>: Use the right-click menu to switch between dark/light themes</li><li><strong>Keyboard Shortcuts</strong>: The test interface supports spacebar repeat, arrow key navigation, ESC pause</li></ul><h2 id="open-source-address" tabindex="-1">Open Source Address <a class="header-anchor" href="#open-source-address" aria-label="Permalink to &quot;Open Source Address&quot;">​</a></h2><h3 id="code-repository" tabindex="-1">Code Repository <a class="header-anchor" href="#code-repository" aria-label="Permalink to &quot;Code Repository&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/dongzheyu/English_Listen" target="_blank" rel="noreferrer">https://github.com/dongzheyu/English_Listen</a></li><li><strong>Gitee</strong>: <a href="https://gitee.com/jetcpp/english_-listen" target="_blank" rel="noreferrer">https://gitee.com/jetcpp/english_-listen</a></li></ul><h3 id="project-information" tabindex="-1">Project Information <a class="header-anchor" href="#project-information" aria-label="Permalink to &quot;Project Information&quot;">​</a></h3><ul><li><strong>Issue Feedback</strong>: <a href="https://github.com/dongzheyu/English_Listen/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li><strong>Feature Suggestions</strong>: <a href="https://github.com/dongzheyu/English_Listen/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></li></ul><h2 id="download-address" tabindex="-1">Download Address <a class="header-anchor" href="#download-address" aria-label="Permalink to &quot;Download Address&quot;">​</a></h2><h3 id="latest-version" tabindex="-1">Latest Version <a class="header-anchor" href="#latest-version" aria-label="Permalink to &quot;Latest Version&quot;">​</a></h3><ul><li><strong>Version</strong>: v2.5.0</li><li><strong>Release Date</strong>: 2026-02-16</li><li><strong>Download Link</strong>: <a href="https://gitee.com/jetcpp/english_-listen/releases/download/2.5.0/EnglishListenSetup.exe" target="_blank" rel="noreferrer">Click to Download</a></li><li><strong>File Size</strong>: 15.2MB</li><li><strong>Checksum</strong>: SHA256:<code>b04afcb75473d31fe04eb6e539bfb6997994cd617002b63933acadeeb9880bb7</code></li></ul><h3 id="version-description" tabindex="-1">Version Description <a class="header-anchor" href="#version-description" aria-label="Permalink to &quot;Version Description&quot;">​</a></h3><p>This version has completed all the features planned in the TODO list, including keyboard shortcut support, learning progress visualization, improved temporary vocabulary mechanism, user account system, data encryption, and privacy settings. It is the most complete and stable version.</p><h2 id="update-records" tabindex="-1">Update Records <a class="header-anchor" href="#update-records" aria-label="Permalink to &quot;Update Records&quot;">​</a></h2><h3 id="v2-5-0-2026-02-16" tabindex="-1">v2.5.0 (2026-02-16) <a class="header-anchor" href="#v2-5-0-2026-02-16" aria-label="Permalink to &quot;v2.5.0 (2026-02-16)&quot;">​</a></h3><ul><li>✅ Completed all features in the v2.5 version development plan</li><li>✅ Core feature enhancements: <ul><li>✅ Implemented vocabulary group management functionality, supporting creation, editing, and deletion of vocabulary groups</li><li>✅ Enhanced vocabulary import/export functionality, supporting CSV, Excel and other common formats</li><li>✅ Improved learning progress statistics functionality, added visualization charts to display learning data</li><li>✅ Implemented vocabulary search and filtering functionality, providing quick search and classification filtering features</li></ul></li><li>✅ Experience optimization: <ul><li>✅ Optimized interface interaction experience, added button hover effects and transition animations</li><li>✅ Improved error handling mechanism, enhanced program stability and error prompts</li><li>✅ Optimized program performance, improved vocabulary loading speed and response speed</li></ul></li><li>✅ Release preparation: <ul><li>✅ Conducted comprehensive testing to ensure normal operation of functions</li><li>✅ Updated project documentation, improved feature descriptions and usage guides</li></ul></li></ul><h3 id="v2-4-0-2026-02-16" tabindex="-1">v2.4.0 (2026-02-16) <a class="header-anchor" href="#v2-4-0-2026-02-16" aria-label="Permalink to &quot;v2.4.0 (2026-02-16)&quot;">​</a></h3><ul><li>✅ Completed all features planned in the TODO list</li><li>✅ Implemented complete user experience improvement list <ul><li>✅ Added keyboard shortcut support (spacebar repeat reading, arrow key word switching, etc.)</li><li>✅ Implemented learning progress visualization functionality, displaying learning progress and trends in chart form</li><li>✅ Improved temporary vocabulary mechanism, allowing dictation to start without manually creating vocabulary</li></ul></li><li>✅ Enhanced interface animation effects, added more smooth transition animations</li><li>✅ Implemented user account system, supporting creation of personal accounts to manage learning data</li><li>✅ Added data encryption functionality, encrypting sensitive user data for storage</li><li>✅ Implemented privacy settings, allowing users to control data sharing permissions</li></ul><h3 id="v2-3-2-2026-12-20" tabindex="-1">v2.3.2 (2026-12-20) <a class="header-anchor" href="#v2-3-2-2026-12-20" aria-label="Permalink to &quot;v2.3.2 (2026-12-20)&quot;">​</a></h3><ul><li>Added online dictation mode, supporting the function of dictating first and submitting answers uniformly</li><li>In online dictation mode, users can input heard words while listening and check results uniformly at the end</li><li>Optimized dictation test user experience, supporting cached input and unified verification at the end</li><li>Improved test result display, providing more detailed correct/incorrect statistics</li><li>Refactored dictation mode selection logic, allowing users to choose paper-and-pencil mode or online mode when starting the test</li></ul><h3 id="v2-3-1-2026-11-15" tabindex="-1">v2.3.1 (2026-11-15) <a class="header-anchor" href="#v2-3-1-2026-11-15" aria-label="Permalink to &quot;v2.3.1 (2026-11-15)&quot;">​</a></h3><ul><li>Fixed learning progress visualization interface layout issue, moved the back button above the chart</li><li>Optimized progress interface layout structure, improved user experience</li><li>Automatically created and synchronized temporary vocabulary files when editing in the view words interface</li><li>Real-time monitoring of editing content changes and synchronization to temporary files</li><li>Automatically deleted temporary vocabulary files upon exit</li><li>Supported starting dictation tests directly from the view words page</li><li>Added learning progress visualization functionality, displaying learning progress and trends in chart form</li><li>Recorded results of each test (time, total words, correct count, accuracy rate)</li><li>Displayed accuracy rate trends through line charts</li><li>Supported saving and loading of test history records</li><li>Accessed learning progress interface through the right-click menu of the settings button</li><li>Added keyboard shortcut support functionality, allowing keyboard shortcuts to control the dictation process in the test interface</li><li>Added keyboard shortcut instructions in the user guide</li><li>Added SHORTCUTS.md document detailing keyboard shortcut usage methods</li></ul><h3 id="v2-3-0-2026-10-08" tabindex="-1">v2.3.0 (2026-10-08) <a class="header-anchor" href="#v2-3-0-2026-10-08" aria-label="Permalink to &quot;v2.3.0 (2026-10-08)&quot;">​</a></h3><ul><li>Fixed Flite voice engine invalid library reference issue, removed invalid link to flite library in CMakeLists.txt</li><li>Optimized project build configuration, improved build efficiency and stability</li><li>Updated version information to v2.3.0</li></ul><hr><p><em>Make English learning simpler and more fun!</em></p>',58)])])}const p=t(r,[["render",o]]);export{g as __pageData,p as default};
